#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Function to extract metadata from PDF
sub extract_metadata {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Get the document information dictionary
    my $info = $pdf->info;

    # Extract metadata
    my $author = $info->get('Author');
    my $title = $info->get('Title');
    my $creation_date = $info->get('CreationDate');

    return ($author, $title, $creation_date);
}

# Function to extract text from a PDF page
sub extract_text {
    my ($pdf_file, $page_num) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Get the page
    my $page = $pdf->page($page_num);

    # Extract text from the page
    my $text = $page->text();

    return $text;
}

